arguments.file_text:
namespace sv_795e9d20e3a349b3849d81e35b6054dc.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@page "/chat"
@rendermode InteractiveServer
@using sv_795e9d20e3a349b3849d81e35b6054dc.Services
@inject IChatService ChatService
@inject IJSRuntime JS

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    @* ── Left sidebar: channel list ── *@
    <aside class="channel-sidebar">
        <div class="sidebar-header">
            <h3>Channels</h3>
        </div>
        <ul class="channel-list">
            @if (_channels is not null)
            {
                @foreach (var channel in _channels)
                {
                    <li class="channel-item @(channel.Id == _activeChannelId ? "active" : "")"
                        @onclick="() => SelectChannelAsync(channel)">
                        <div class="channel-name"># @channel.Name</div>
                        <div class="channel-desc">@TruncateDescription(channel.Description)</div>
                        @if (channel.UnreadCount > 0)
                        {
                            <span class="unread-badge">@channel.UnreadCount</span>
                        }
                    </li>
                }
            }
        </ul>
    </aside>

    @* ── Main message area ── *@
    <main class="message-area @(_threadOpen ? "" : "full-width")">
        @if (_activeChannel is not null)
        {
            <div class="message-header">
                <h2># @_activeChannel.Name</h2>
                <span class="channel-description">@_activeChannel.Description</span>
            </div>

            <div class="message-list" @ref="_messageListRef" @onscroll="HandleScrollAsync">
                @if (_loadingMore)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @if (_messages is not null)
                {
                    @foreach (var msg in _messages)
                    {
                        <div class="message-bubble" @onmouseenter="() => _hoveredMessageId = msg.Id"
                             @onmouseleave="() => _hoveredMessageId = null">
                            <div class="message-meta">
                                <span class="author">@msg.Author</span>
                                <span class="timestamp">@FormatRelativeTime(msg.SentAt)</span>
                            </div>
                            <div class="message-content">@msg.Content</div>

                            @if (msg.Reactions.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var r in msg.Reactions)
                                    {
                                        <button class="reaction-badge" title="@string.Join(", ", r.Users)"
                                                @onclick="() => ToggleReactionAsync(msg.Id, r.Emoji)">
                                            @r.Emoji @r.Users.Count
                                        </button>
                                    }
                                </div>
                            }

                            @if (_threadSummaries.TryGetValue(msg.Id, out var summary))
                            {
                                <button class="thread-link" @onclick="() => OpenThreadAsync(msg)">
                                    @summary.ReplyCount @(summary.ReplyCount == 1 ? "reply" : "replies")
                                </button>
                            }

                            @if (_hoveredMessageId == msg.Id)
                            {
                                <div class="message-actions">
                                    <button class="action-btn" title="Reply in thread"
                                            @onclick="() => OpenThreadAsync(msg)">💬 Reply</button>
                                    <button class="action-btn" title="Add reaction"
                                            @onclick="() => ToggleEmojiPicker(msg.Id)">😀 React</button>
                                </div>
                            }

                            @if (_emojiPickerMessageId == msg.Id)
                            {
                                <div class="emoji-picker">
                                    @foreach (var emoji in _quickEmojis)
                                    {
                                        <button class="emoji-option"
                                                @onclick="() => PickEmojiAsync(msg.Id, emoji)">@emoji</button>
                                    }
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea @bind="_newMessageText" @bind:event="oninput"
                          placeholder="Message #@_activeChannel.Name"
                          @onkeydown="HandleMessageKeyDownAsync"
                          rows="2"></textarea>
                <button class="send-btn" disabled="@string.IsNullOrWhiteSpace(_newMessageText)"
                        @onclick="SendMessageAsync">Send</button>
            </div>
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </main>

    @* ── Right panel: thread view ── *@
    @if (_threadOpen && _threadRootMessage is not null)
    {
        <aside class="thread-panel">
            <div class="thread-header">
                <h3>Thread</h3>
                <button class="close-btn" @onclick="CloseThread" title="Close thread">✕</button>
            </div>
            <div class="thread-root-quote">
                <span class="author">@_threadRootMessage.Author</span>
                <p>@_threadRootMessage.Content</p>
            </div>
            <div class="thread-replies">
                @if (_threadReplies is not null)
                {
                    @foreach (var reply in _threadReplies)
                    {
                        <div class="message-bubble thread-reply">
                            <div class="message-meta">
                                <span class="author">@reply.Author</span>
                                <span class="timestamp">@FormatRelativeTime(reply.SentAt)</span>
                            </div>
                            <div class="message-content">@reply.Content</div>
                            @if (reply.Reactions.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var r in reply.Reactions)
                                    {
                                        <button class="reaction-badge"
                                                title="@string.Join(", ", r.Users)"
                                                @onclick="() => ToggleReactionAsync(reply.Id, r.Emoji)">
                                            @r.Emoji @r.Users.Count
                                        </button>
                                    }
                                </div>
                            }
                        </div>
                    }
                }
            </div>
            <div class="message-input-area">
                <textarea @bind="_threadReplyText" @bind:event="oninput"
                          placeholder="Reply…"
                          @onkeydown="HandleThreadKeyDownAsync"
                          rows="2"></textarea>
                <button class="send-btn" disabled="@string.IsNullOrWhiteSpace(_threadReplyText)"
                        @onclick="SendThreadReplyAsync">Reply</button>
            </div>
        </aside>
    }
</div>

@code {
    private const int PageSize = 30;
    private static readonly string[] _quickEmojis = ["👍", "❤️", "😂", "🎉", "🚀", "👀"];

    private List<Channel>? _channels;
    private int? _activeChannelId;
    private Channel? _activeChannel;

    private List<Message>? _messages;
    private int _skip;
    private bool _loadingMore;
    private bool _allMessagesLoaded;

    private Dictionary<int, ThreadSummary> _threadSummaries = new();

    private int? _hoveredMessageId;
    private int? _emojiPickerMessageId;

    private string _newMessageText = "";

    // Thread state
    private bool _threadOpen;
    private Message? _threadRootMessage;
    private List<Message>? _threadReplies;
    private string _threadReplyText = "";

    private ElementReference _messageListRef;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
    }

    private async Task SelectChannelAsync(Channel channel)
    {
        if (_activeChannelId == channel.Id) return;

        _activeChannelId = channel.Id;
        _activeChannel = channel;
        _skip = 0;
        _allMessagesLoaded = false;
        _messages = null;
        _threadSummaries.Clear();
        _emojiPickerMessageId = null;

        var messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        _messages = messages;
        _skip = messages.Count;

        await BuildThreadSummariesAsync(messages);
        await ChatService.MarkChannelReadAsync(channel.Id);
        await RefreshChannelUnread(channel.Id);

        await ScrollToBottomAsync();
    }

    private async Task BuildThreadSummariesAsync(IEnumerable<Message> messages)
    {
        foreach (var msg in messages.Where(m => m.ReplyToId is null))
        {
            var thread = await ChatService.GetThreadAsync(msg.Id);
            if (thread.Count > 0)
            {
                _threadSummaries[msg.Id] = new ThreadSummary(
                    msg.Id,
                    thread.Count,
                    thread.Max(t => t.SentAt));
            }
        }
    }

    private async Task HandleScrollAsync()
    {
        if (_loadingMore || _allMessagesLoaded || _activeChannelId is null) return;

        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list')?.scrollTop ?? 1");
        if (scrollTop > 50) return;

        _loadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_activeChannelId.Value, _skip, PageSize);
        if (older.Count == 0)
        {
            _allMessagesLoaded = true;
        }
        else
        {
            _messages!.InsertRange(0, older);
            _skip += older.Count;
            await BuildThreadSummariesAsync(older);
        }

        _loadingMore = false;
    }

    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(_newMessageText) || _activeChannelId is null) return;

        var sent = await ChatService.SendMessageAsync(_activeChannelId.Value, _newMessageText.Trim(), null);
        _messages ??= new();
        _messages.Add(sent);
        _skip++;
        _newMessageText = "";

        await ScrollToBottomAsync();
    }

    private async Task HandleMessageKeyDownAsync(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMessageAsync();
        }
    }

    private async Task OpenThreadAsync(Message rootMessage)
    {
        _threadRootMessage = rootMessage;
        _threadReplies = await ChatService.GetThreadAsync(rootMessage.Id);
        _threadOpen = true;
        _threadReplyText = "";
        _emojiPickerMessageId = null;
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadReplies = null;
        _threadReplyText = "";
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(_threadReplyText) || _threadRootMessage is null || _activeChannelId is null)
            return;

        var reply = await ChatService.SendMessageAsync(_activeChannelId.Value, _threadReplyText.Trim(), _threadRootMessage.Id);
        _threadReplies ??= new();
        _threadReplies.Add(reply);
        _threadReplyText = "";

        // Update the thread summary in the main view
        if (_threadSummaries.TryGetValue(_threadRootMessage.Id, out var existing))
        {
            _threadSummaries[_threadRootMessage.Id] = existing with
            {
                ReplyCount = existing.ReplyCount + 1,
                LastReplyAt = reply.SentAt
            };
        }
        else
        {
            _threadSummaries[_threadRootMessage.Id] = new ThreadSummary(_threadRootMessage.Id, 1, reply.SentAt);
        }
    }

    private async Task HandleThreadKeyDownAsync(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendThreadReplyAsync();
        }
    }

    private void ToggleEmojiPicker(int messageId)
    {
        _emojiPickerMessageId = _emojiPickerMessageId == messageId ? null : messageId;
    }

    private async Task PickEmojiAsync(int messageId, string emoji)
    {
        await ToggleReactionAsync(messageId, emoji);
        _emojiPickerMessageId = null;
    }

    private async Task ToggleReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);

        // Refresh the single message in the list
        if (_activeChannelId is not null && _messages is not null)
        {
            var idx = _messages.FindIndex(m => m.Id == messageId);
            if (idx >= 0)
            {
                var refreshed = await ChatService.GetMessagesAsync(_activeChannelId.Value, 0, _skip);
                var updated = refreshed.FirstOrDefault(m => m.Id == messageId);
                if (updated is not null) _messages[idx] = updated;
            }
        }

        // Also refresh thread replies if it's a thread message
        if (_threadReplies is not null)
        {
            var idx = _threadReplies.FindIndex(m => m.Id == messageId);
            if (idx >= 0 && _threadRootMessage is not null)
            {
                var refreshed = await ChatService.GetThreadAsync(_threadRootMessage.Id);
                var updated = refreshed.FirstOrDefault(m => m.Id == messageId);
                if (updated is not null) _threadReplies[idx] = updated;
            }
        }
    }

    private async Task RefreshChannelUnread(int channelId)
    {
        if (_channels is null) return;
        var fresh = await ChatService.GetChannelsAsync();
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            var updated = fresh.FirstOrDefault(c => c.Id == channelId);
            if (updated is not null) _channels[idx] = updated;
        }
    }

    private async Task ScrollToBottomAsync()
    {
        await Task.Yield();
        await JS.InvokeVoidAsync("eval",
            "let el = document.querySelector('.message-list'); if(el) el.scrollTop = el.scrollHeight;");
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 172800 => "yesterday",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }

    private static string TruncateDescription(string description)
    {
        return description.Length <= 40 ? description : description[..37] + "…";
    }
}

