+    border-radius: 4px;
+    transition: background 0.1s;
+}
+
+.emoji-option:hover {
+    background: #f0f0f0;
+}
+
+/* ── Message input ── */
+.message-input-area {
+    padding: 10px 20px;
+    border-top: 1px solid #ddd;
+    display: flex;
+    gap: 8px;
+    flex-shrink: 0;
+}
+
+.message-input-area textarea {
+    flex: 1;
+    resize: none;
+    border: 1px solid #ccc;
+    border-radius: 6px;
+    padding: 8px 12px;
+    font-size: 0.9rem;
+    font-family: inherit;
+    outline: none;
+    transition: border-color 0.15s;
+}
+
+.message-input-area textarea:focus {
+    border-color: #1264a3;
+}
+
+.send-btn {
+    background: #007a5a;
+    color: #fff;
+    border: none;
+    border-radius: 6px;
+    padding: 8px 18px;
+    font-weight: 600;
+    font-size: 0.9rem;
+    cursor: pointer;
+    align-self: flex-end;
+    transition: background 0.15s;
+}
+
+.send-btn:hover:not(:disabled) {
+    background: #005e47;
+}
+
+.send-btn:disabled {
+    background: #ccc;
+    cursor: not-allowed;
+}
+
+/* ── Thread panel ── */
+.thread-panel {
+    width: 25%;
+    min-width: 250px;
+    background: #fff;
+    display: flex;
+    flex-direction: column;
+    border-left: 1px solid #ddd;
+    overflow: hidden;
+}
+
+.thread-header {
+    display: flex;
+    justify-content: space-between;
+    align-items: center;
+    padding: 12px 16px;
+    border-bottom: 1px solid #ddd;
+    flex-shrink: 0;
+}
+
+.thread-header h3 {
+    margin: 0;
+    font-size: 1rem;
+}
+
+.close-btn {
+    background: none;
+    border: none;
+    font-size: 1.2rem;
+    cursor: pointer;
+    color: #666;
+    padding: 4px 8px;
+    border-radius: 4px;
+}
+
+.close-btn:hover {
+    background: #f0f0f0;
+    color: #333;
+}
+
+.thread-root-quote {
+    padding: 12px 16px;
+    background: #f9f9f9;
+    border-bottom: 1px solid #eee;
+    flex-shrink: 0;
+}
+
+.thread-root-quote .author {
+    font-size: 0.85rem;
+}
+
+.thread-root-quote p {
+    margin: 4px 0 0;
+    font-size: 0.88rem;
+    color: #444;
+}
+
+.thread-replies {
+    flex: 1;
+    overflow-y: auto;
+    padding: 8px 16px;
+}
+
+.thread-reply {
+    padding: 6px 10px;
+}
+

